def valid_identifier(value):
    return isinstance(value, str) and bool(IDENTIFIER_RE.match(value))


def quote_ident(name):
    if not valid_identifier(name):
        raise ValueError(f"Invalid identifier: {name}")
    return psycopg2.extensions.quote_ident(name, None)


def normalize_logical(value):
    if not isinstance(value, str):
        raise ValueError("Invalid logical operator")
    v = value.upper()
    if v not in LOGICALS:
        raise ValueError("Invalid logical operator")
    return v


def normalize_operator(value):
    if not isinstance(value, str):
        raise ValueError("Invalid operator")
    v = value.upper().strip()
    if v not in OPS:
        raise ValueError("Invalid operator")
    return v


def build_where_clause(filters):
    if not filters:
        return "", []

    clauses = []
    params = []

    if isinstance(filters, dict):
        filters = [filters]

    for idx, f in enumerate(filters):
        if not isinstance(f, dict):
            raise ValueError("Each filter must be an object")

        column = f.get("column")
        operator = normalize_operator(f.get("operator", "="))
        value = f.get("value")
